"""
frequency.py — Named Frequency Families

Maps human-readable operational contexts to phase angles in [-π, π].
Using named families instead of raw floats prevents magic-number drift
and makes registry state auditable at a glance.

Separation between families is π/6 (30°), giving six orthogonal bands
with enough angular distance that cos(Δφ) ≤ 0.87 between neighbours
and ≤ 0.0 between families separated by two steps or more — safe
destructive-interference margins for the coherence shield.
"""

from __future__ import annotations

import math
from enum import Enum


class FrequencyFamily(float, Enum):
    """Operational context → phase angle (radians)."""

    NEUTRAL   = 0.0               # baseline / unclassified
    NORMAL    = math.pi / 6       # steady-state operation  (30°)
    ALERT     = math.pi / 3       # anomaly detected        (60°)
    EMERGENCY = math.pi / 2       # active failure / crisis  (90°)
    RECOVERY  = 2 * math.pi / 3   # remediation in progress (120°)
    ARCHIVE   = math.pi           # historical / cold data  (180°)

    # ------------------------------------------------------------------ #
    def angular_distance(self, other: "FrequencyFamily") -> float:
        """Absolute angular separation between two families (radians)."""
        return abs(self.value - other.value)

    def cosine_coupling(self, other: "FrequencyFamily") -> float:
        """
        Expected cos(Δφ) between two families.
        1.0  → perfect constructive interference
        0.0  → orthogonal — signal nulled
        -1.0 → full destructive interference
        """
        return math.cos(self.angular_distance(other))

    @classmethod
    def nearest(cls, phi: float) -> "FrequencyFamily":
        """Return the named family closest to an arbitrary phase angle."""
        return min(cls, key=lambda f: abs(f.value - phi))

    @classmethod
    def from_label(cls, label: str) -> "FrequencyFamily":
        """Case-insensitive lookup by name."""
        try:
            return cls[label.upper()]
        except KeyError:
            raise ValueError(
                f"Unknown frequency family '{label}'. "
                f"Valid names: {[f.name for f in cls]}"
            )


# Convenience aliases so callers can import flat names if preferred.
NEUTRAL   = FrequencyFamily.NEUTRAL
NORMAL    = FrequencyFamily.NORMAL
ALERT     = FrequencyFamily.ALERT
EMERGENCY = FrequencyFamily.EMERGENCY
RECOVERY  = FrequencyFamily.RECOVERY
ARCHIVE   = FrequencyFamily.ARCHIVE
